const status = $('Buscar Status').first().json;
const leadsData = $('Buscar Leads').first().json;
const leads = leadsData.leads || [];

const hoje = new Date();
const inicioSemana = new Date(hoje);
inicioSemana.setDate(hoje.getDate() - 7);

let texto = `📊 *RELATÓRIO SEMANAL*\n`;
texto += `${inicioSemana.toLocaleDateString('pt-BR')} a ${hoje.toLocaleDateString('pt-BR')}\n\n`;

texto += `📱 *WhatsApp:* ${status.whatsapp?.conectado ? '✅ Conectado' : '❌ Desconectado'}\n\n`;

texto += `👥 *Contatos:*\n`;
texto += `• Total: ${status.contatos?.total || 0}\n`;
texto += `• Pendentes: ${status.contatos?.pendente || 0}\n`;
texto += `• Responderam: ${status.contatos?.respondeu || 0}\n`;
texto += `• Leads: ${status.contatos?.lead || 0}\n`;
texto += `• Sem interesse: ${status.contatos?.naoInteresse || 0}\n\n`;

texto += `📈 *Campanhas:*\n`;
texto += `• Total: ${status.campanhas?.total || 0}\n`;
texto += `• Ativas: ${status.campanhas?.ativa || 0}\n`;
texto += `• Concluídas: ${status.campanhas?.concluida || 0}\n\n`;

if (leads.length > 0) {
  texto += `🔥 *Leads Quentes (últimos 7 dias):*\n`;
  for (const lead of leads.slice(0, 10)) {
    texto += `• ${lead.contato?.nome || 'Sem nome'} - ${lead.contato?.telefone || '-'}`;
    if (lead.interesse) texto += ` (${lead.interesse})`;
    texto += `\n`;
  }
} else {
  texto += `🔥 *Leads:* Nenhum lead novo na semana\n`;
}

texto += `\n✅ Relatório gerado automaticamente pelo n8n`;

return [{ json: { texto, resumo: { contatos: status.contatos?.total || 0, leads: leads.length, campanhas: status.campanhas?.total || 0 } } }];
